member.example:
Bind the Toggle's isOn state to a boolean ViewModel property using a serialized binder field — the target Toggle is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ToggleIsOnBinder _isAccepted;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isAccepted;
    }


Bind the Toggle's isOn state to a boolean ViewModel property by constructing the binder in code, with value inversion.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Toggle _target;
        
        private ToggleIsOnBinder IsAccepted =>
            new(_target, isInvert: true);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isAccepted;
    }

Bind the Toggle's isOn state to a boolean ViewModel property using a MonoBinder component assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ToggleIsOnMonoBinder _isAccepted;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isAccepted;
    }
